#include <bits/stdc++.h>
using namespace std;

const int N = 1e3 + 5;
int x[N][N], y[N][N], z[N][N];

int read() {
  int x = 0, w = 1;
  char ch = 0;
  while (ch < '0' || ch > '9') {  
    if (ch == '-') w = -1;        
    ch = getchar();              
  }
  while (ch >= '0' && ch <= '9') {  
    x = x * 10 + (ch - '0');  
	ch = getchar();  
  }
  return x * w; 
}

void write(int x) {
  static int sta[35];
  int top = 0;
  do {
    sta[top++] = x % 10, x /= 10;
  } while (x);
  while (top) putchar(sta[--top] + 48);
  putchar('\n');
}

int main() {
	int n, q, ans = 0;
	n = read();q = read();
	for (int i = 1; i <= q; i++) {
		int a, b, c;
		a = read();
		b = read();
		c = read();
		if (++x[a][b] == n) ans++;
		if (++y[a][c] == n) ans++;
		if (++z[b][c] == n) ans++;
		write(ans);
	}
	return 0;
}
